-- Ken's Hardened V2 Fix

local b64_0xl1l1lI = {}
local char_0xlIIIIl='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xllll11=1,#char_0xlIIIIl do b64_0xl1l1lI[char_0xlIIIIl:sub(i_0xllll11,i_0xllll11)] = i_0xllll11 - 1 end

function b64_0xl1l1lI.dec_0xlllIll(d_0xIlIIlI)
    d_0xIlIIlI = string.gsub(d_0xIlIIlI, '[^'..char_0xlIIIIl..'=]', '')
    local r_0xlI1II1 = {}
    for i_0xllll11=1, #d_0xIlIIlI, 4 do
        local c_0x1IIl1I = b64_0xl1l1lI[d_0xIlIIlI:sub(i_0xllll11,i_0xllll11)] or 0
        local c_0xlIllI1 = b64_0xl1l1lI[d_0xIlIIlI:sub(i_0xllll11+1,i_0xllll11+1)] or 0
        local c_0xIllI1I, c_0x1IlllI = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIlIIlI:sub(i_0xllll11+2,i_0xllll11+2)
        if ch3 == "=" then has3 = false else c_0xIllI1I = b64_0xl1l1lI[ch3] or 0 end
        local ch4 = d_0xIlIIlI:sub(i_0xllll11+3,i_0xllll11+3)
        if ch4 == "=" then has4 = false else c_0x1IlllI = b64_0xl1l1lI[ch4] or 0 end
        local b_0x1lllIl = c_0x1IIl1I * (2^18) + c_0xlIllI1 * (2^12) + c_0xIllI1I * (2^6) + c_0x1IlllI
        local b_0xl11111 = math.floor(b_0x1lllIl / (2^16)) % (2^8)
        local b_0xI11IlI = math.floor(b_0x1lllIl / (2^8)) % (2^8)
        local b_0xI1ll1l = b_0x1lllIl % (2^8)
        table.insert(r_0xlI1II1, string.char(b_0xl11111))
        if has3 then table.insert(r_0xlI1II1, string.char(b_0xI11IlI)) end
        if has4 then table.insert(r_0xlI1II1, string.char(b_0xI1ll1l)) end
    end
    return table.concat(r_0xlI1II1)
end


local function bxor_0xlllIl1(a_0xl1Ill1,b_0x1l1l1l)
    if bit32 then return bit32.bxor(a_0xl1Ill1,b_0x1l1l1l) end
    local r_0xlIl1II = 0
    for i_0xIIlIll = 0, 7 do
        local x_0xIIl1lI = a_0xl1Ill1 % 2
        local y_0xllIlII = b_0x1l1l1l % 2
        if x_0xIIl1lI ~= y_0xllIlII then r_0xlIl1II = r_0xlIl1II + (2^i_0xIIlIll) end
        a_0xl1Ill1 = math.floor(a_0xl1Ill1 / 2)
        b_0x1l1l1l = math.floor(b_0x1l1l1l / 2)
    end
    return r_0xlIl1II
end


local function bxor_str_0x1l1I1l(s_0xlII1lI, k_0xlIlIIl)
    local r_0xlllIlI = {}
    for i_0xlIII11=1, #s_0xlII1lI do
        local b_0x1llll1 = string.byte(s_0xlII1lI, i_0xlIII11)
        local kb_0xlI11I1 = string.byte(k_0xlIlIIl, (i_0xlIII11-1) % #k_0xlIlIIl + 1)
        r_0xlllIlI[i_0xlIII11] = string.char(bxor_0xlllIl1(b_0x1llll1, kb_0xlI11I1))
    end
    return table.concat(r_0xlllIlI)
end


local function getkeys_0xIllll1()
    local seed = b64_0xl1l1lI.dec_0xlllIll("UWcyeXN2aEs=")
    local k1_enc = b64_0xl1l1lI.dec_0xlllIll("Cz9ADB8EXj0=")
    local k2_enc = b64_0xl1l1lI.dec_0xlllIll("ZwpVADsCK3M=")
    return bxor_str_0x1l1I1l(k1_enc, seed), bxor_str_0x1l1I1l(k2_enc, seed)
end


local function cff_0x1I1Ill(a_0xIllIll)
    local st_0xIlI1lI = 0
    local res_0xI1Il1l = a_0xIllIll
    while true do
        if st_0xIlI1lI == 0 then
            res_0xI1Il1l = res_0xI1Il1l + 1
            st_0xIlI1lI = 1
        elseif st_0xIlI1lI == 1 then
            res_0xI1Il1l = res_0xI1Il1l * 2
            st_0xIlI1lI = 2
        elseif st_0xIlI1lI == 2 then
            res_0xI1Il1l = res_0xI1Il1l - 3
            st_0xIlI1lI = 3
        else
            break
        end
    end
    return res_0xI1Il1l
end


local function chain_0xIlII1l(x) return x*2 end
local function chain_0xIIlllI(x) return chain_0xIlII1l(x)+1 end


local d_0xIlIIll = {
  {op=255, val="", is_enc=true},
}
local pc_0xIlIII1 = 1
local stk_0xIIIIll = {}
stk_0xIIIIll._jmp = nil


local disp_0xll1lII = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIllll1()

local state_0x1lIlII = 0
while true do
    if state_0x1lIlII == 0 then  -- FETCH
        if pc_0xIlIII1 > #d_0xIlIIll then break end
        local inst = d_0xIlIIll[pc_0xIlIII1]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xl1l1lI.dec_0xlllIll(val)
            d = bxor_str_0x1l1I1l(d, k2)
            val = bxor_str_0x1l1I1l(d, k1)
        end
        stk_0xIIIIll._jmp = nil
        pc_0xIlIII1 = pc_0xIlIII1 + 1
        cur_op_0x1I1Ill = opcode
        cur_val_0xlllI1I = val
        state_0x1lIlII = 1

    elseif state_0x1lIlII == 1 then  -- EXECUTE
        local handler = disp_0xll1lII[cur_op_0x1I1Ill]
        if handler then
            handler(stk_0xIIIIll, cur_val_0xlllI1I)
        end
        if stk_0xIIIIll._jmp then
            pc_0xIlIII1 = pc_0xIlIII1 + stk_0xIIIIll._jmp
        end
        state_0x1lIlII = 0
    else
        break
    end
end
